SELECT COUNT(*) AS desire_count
FROM individual_desires
WHERE individual_id = 1;

SELECT COUNT(user_desire_id) AS active_desire_count
FROM user_desires
WHERE user_id = 1 AND desire_status = 'Active';

SELECT desire_type_id, desire_type_name
FROM desire_types
WHERE desire_type_name = 'Basic Needs';

SELECT DISTINCT user_id
FROM user_desires
WHERE desire_status = 'Active';

SELECT desire_id, desire_category_id
FROM desires
WHERE sickness_desire = 1 AND weight > 5;
